class Solution {
public:
    int findBestValue(vector<int>& arr, int target) {
        sort(arr.begin(), arr.end());
        int sum = 0, res = 0, min_diff = INT_MAX;
        for (int i = 0; i < arr.size(); i++) {
            sum += arr[i];
            if (sum > target) {
                int diff = abs(sum - target);
                if (diff < min_diff) {
                    min_diff = diff;
                    res = arr[i - 1];
                }
                break;
            }
        }
        return res;
    }
};
